vector<int> g[N];
int dep[N], fat[N], son[N], siz[N];
int top[N], dfn[N], rnk[N], tim; // 链顶、节点对应时间戳、时间戳对应节点(线段树用)、时间戳
void solve(int CASE)
{
	ll n, m, a; cin >> n >> m >> a;
	a = (a % mod + mod) % mod;
	fa(i, 2, n) {
		int f; cin >> f;
		g[f].pb(i), g[i].pb(f);
	}

	// ========== 重链剖分 ========== //

	// dfs1：初始化 深度、父节点、子树大小、重儿子
	var dfs1 = [&](var dfs, int now, int fa, int d)->void {
		dep[now] = d, fat[now] = fa, siz[now] = 1, son[now] = 0;
		int max_siz = -1;
		for (int to : g[now]) {
			if (to == fa)continue;
			dfs(dfs, to, now, d + 1);
			siz[now] += siz[to];
			if (max_siz < siz[to]) {
				max_siz = siz[to];
				son[now] = to;
			}
		}
		};

	// 构造重链剖分
	tim = 0; // 时间戳从 1 开始
	var dfs2 = [&](var dfs, int now, int t)->void {
		// t：当前链链顶
		top[now] = t, dfn[now] = ++tim, rnk[tim] = now;
		if (!son[now])return;  // 如果没有重儿子，说明是叶子

		// 1. 优先处理重儿子，链顶不变延续当前链
		dfs(dfs, son[now], t);

		// 2. 处理轻儿子，轻儿子为链顶新开一条链
		for (int to : g[now]) {
			if (to == son[now] or to == fat[now])continue;
			dfs(dfs, to, to);
		}
		};

	dfs1(dfs1, 1, 0, 1);
	dfs2(dfs2, 1, 1);

	var t = MT::BitTree<ll>(n + 1, mod);

	// 子树修改 O(logN)
	var update_subtree = [&](MT::BitTree<ll>& t, int x, ll k)->void {
		// 子树在 dfs 序中是连续区间 [ dfn[x], dfn[x] + siz[x] - 1 ]
		t.updateRange(dfn[x], dfn[x] + siz[x] - 1, k);
		};
	// 子树查询 O(logN)
	var query_subtree = [&](MT::BitTree<ll>& t, int x)->ll {
		ll res = 0;
		int l = dfn[x], r = dfn[x] + siz[x] - 1;
		return t.queryRange(l, r);
		};

	// ============================= //

	while (m--) {
		int op; cin >> op;
		if (op == 1) {
			ll u, x; cin >> u >> x;
			// += a ^ (x - dep[u]) * a ^ dep[v]
			// 处理修改中的常量 a ^ (x - dep[u])
			if (x - dep[u] > 0)
				update_subtree(t, u, Math::fastPow(a, x - dep[u], mod));
			else if (x - dep[u] < 0)
				update_subtree(t, u, Math::inv(Math::fastPow(a, dep[u] - x, mod), mod));
			else
				update_subtree(t, u, 1);
		}
		else {
			int u; cin >> u;
			// += a ^ (x - dep[u]) * a ^ dep[v]
			// 处理查询中的常量 a ^ dep[v]
			cout << t.queryRange(dfn[u], dfn[u]) * Math::fastPow(a, dep[u], mod) % mod << endl;
		}
	}
	return;
}
